using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int M1=985311787,M2=985387769;
struct Hash
{
	int h1,h2;inline Hash(int H1=0,int H2=0){h1=H1;h2=H2;}
	inline Hash friend operator * (const Hash &x,const Hash &y){return Hash(1ll*x.h1*y.h1%M1,1ll*x.h2*y.h2%M2);}
	inline Hash friend operator * (const Hash &x,const int &y){return Hash(1ll*x.h1*y%M1,1ll*x.h2*y%M2);}
	inline Hash friend operator * (const int &y,const Hash &x){return Hash(1ll*x.h1*y%M1,1ll*x.h2*y%M2);}
	inline Hash friend operator + (const Hash &x,const Hash &y){return Hash((x.h1+y.h1>=M1?x.h1+y.h1-M1:x.h1+y.h1),(x.h2+y.h2>=M2?x.h2+y.h2-M2:x.h2+y.h2));}
	inline Hash friend operator + (const Hash &x,const int &y){return Hash((x.h1+y>=M1?x.h1+y-M1:x.h1+y),(x.h2+y>=M2?x.h2+y-M2:x.h2+y));}
	inline Hash friend operator + (const int &y,const Hash &x){return Hash((x.h1+y>=M1?x.h1+y-M1:x.h1+y),(x.h2+y>=M2?x.h2+y-M2:x.h2+y));}
	inline Hash friend operator - (const Hash &x,const Hash &y)
	{
//		return x+Hash(M1-y.h1,M2-y.h2);
		return Hash((x.h1-y.h1<0?x.h1-y.h1+M1:x.h1-y.h1),(x.h2-y.h2<0?x.h2-y.h2+M2:x.h2-y.h2));
	}
	inline bool operator == (const Hash &x)const {return x.h1==h1&&x.h2==h2;}
};
template<typename T> inline void CV(vector<T> &v){vector<T> t;v.swap(t);}

struct Nd{int l,r,u,v;};
struct ND{int l,r,u1,v1,u2,v2;};vector<ND> A;
const int N=3e5+10,Base=31;
int head[N],des[N<<1],nxt[N<<1],cgt,a[N],n;char ss[N];
vector<int> c[N];int loc[N];Hash pw[N];
inline void ins(int x,int y)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;
}
int dep[N],siz[N],mxs[N],fa[N],top[N],cdt;Hash F[N],I[N];
inline void dfs0(int u=1,int f=0)
{
	int mx=0;siz[u]=1;dep[u]=dep[fa[u]=f]+1;
	F[u]=F[f]*Base+a[u];I[u]=I[f]+a[u]*pw[dep[u]];
	grep(u,i)if(des[i]!=f){int v=des[i];dfs0(v,u);siz[u]+=siz[v];siz[v]>mx?mx=siz[mxs[u]=v]:0;}
}
inline void dfs1(int u=1,int fa=0,int tp=1)
{
	c[top[u]=tp].push_back(u);loc[u]=c[tp].size()-1;if(mxs[u])dfs1(mxs[u],u,tp);
	grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u])dfs1(des[i],u,des[i]);
}
inline int LCA(int u,int v)
{
	while(top[u]!=top[v])dep[top[u]]<dep[top[v]]?v=fa[top[v]]:u=fa[top[u]];
	return dep[u] < dep[v] ? u : v ;
}
inline int Dis(int u,int v){return dep[u]+dep[v]-2*dep[LCA(u,v)]+1;}
vector<Nd> tmp,B,C;
inline Hash H(int u,int v)
{
	if(dep[u]<dep[v])return (F[v]-F[fa[u]]*pw[dep[v]-dep[u]+1])*pw[n-(dep[v]-dep[u]+1)];
	else return (I[u]-I[fa[v]])*pw[n-(dep[u]+1)];
}
inline void GetP(vector<Nd> &V,int u,int v)
{
	CV(tmp);int m=Dis(u,v),g=0;
	while(top[u]!=top[v])
	{
		if(dep[top[u]]<dep[top[v]])
		{
			int len=dep[v]-dep[top[v]]+1;
			tmp.push_back({m-len,m,top[v],v});m-=len;
			v=fa[top[v]];
		}
		else
		{
			int len=dep[u]-dep[top[u]]+1;
			V.push_back({g,g+len,u,top[u]});g+=len;
			u=fa[top[u]];
		}
	}
	if(dep[u]<dep[v])
	{
		int len=dep[v]-dep[u]+1;
		tmp.push_back({m-len,m,u,v});
	}
	else
	{
		int len=dep[u]-dep[v]+1;
		V.push_back({g,g+len,u,v});
	}
	for(unsigned i=tmp.size()-1;~i;--i)V.push_back(tmp[i]);
}
inline int fnd(int u,int v,int d)
{
	if(dep[u]<dep[v])return c[top[u]][loc[u]+d];
	else return c[top[u]][loc[u]-d];
}
inline void merge()
{
	int p1=0,p2=0,pl=0;CV(A);
	while(p1<int(B.size())&&p2<int(C.size()))
	{
		const Nd &b=B[p1],&c=C[p2];
		if(b.r<c.r)
		{
			A.push_back({pl,b.r,fnd(b.u,b.v,pl-b.l),b.v,fnd(c.u,c.v,pl-c.l),fnd(c.u,c.v,pl-c.l+(b.r-pl)-1)});
			pl=b.r;++p1;
		}
		else
		{
			A.push_back({pl,c.r,fnd(b.u,b.v,pl-b.l),fnd(b.u,b.v,pl-b.l+(c.r-pl)-1),fnd(c.u,c.v,pl-c.l),c.v});
			#ifdef DEBUG
			printf("QAQ :: %d %d fnd(%d,%d,%d) fnd(%d,%d,%d)\n",pl,c.r,b.u,b.v,pl-b.l,b.u,b.v,c.r-pl);
			#endif
			pl=c.r;++p2;if(b.r==c.r)++p1;
		}
	}
}
inline int work()
{
	int ans=0;for(ND x:A)
	{
		if(!(H(x.u1,x.v1)==H(x.u2,x.v2)))
		{
			int l=0,r=x.r-x.l;while(l<=r)
			{
				int mid=(l+r)>>1;
				if(H(x.u1,fnd(x.u1,x.v1,mid))==H(x.u2,fnd(x.u2,x.v2,mid)))l=mid+1;
				else r=mid-1;
			}
			#ifdef DEBUG
			printf("CNM :: %d %d %d\n",l,ans,x.l);
			#endif
			return ans+l;
		}
		ans+=x.r-x.l;
	}
	return ans;
}
