int main()
{

//	FIN("data.in");
//	FOUT("mine.out");
	dep[0]=-1;n=read();
	scanf("%s",ss+1);rep(1,n,i)a[i]=ss[i]-'a'+1;
	pw[0]=Hash(1,1);rep(1,n,i)pw[i]=pw[i-1]*Base;
	rep(2,n,i)ins(read(),read()); dfs0();dfs1();
//	printf("QAQ ::::  %d %d\n",H(23,23).h2,H(26,26).h2);
//	printf("QAQ :::: %d %d\n",a[23],a[26]);
	int Q=read();while(Q--)
	{
		int u=read(),v=read();CV(B);GetP(B,u,v);
			u=read();v=read();CV(C);GetP(C,u,v);
		#ifdef DEBUG
		printf("B :: ");for(Nd v:B)printf("{%d,%d,%d,%d} ",v.l,v.r,v.u,v.v);puts("");
		printf("C :: ");for(Nd v:C)printf("{%d,%d,%d,%d} ",v.l,v.r,v.u,v.v);puts("");
		#endif
		merge();
		#ifdef DEBUG
		printf("A :: ");for(ND v:A)printf("{%d,%d,%d,%d,%d,%d} ",v.l,v.r,v.u1,v.v1,v.u2,v.v2);puts("");
		printf("Answer Here ::::  ");
		#endif
		printf("%d\n",work());
	}
}
